const raw = $('Webhook').first().json.body || {};
let enhanced = $input.first().json.message?.content || raw.prompt || 'a cinematic scene';
// Strip any <think>...</think> tags from qwen3 reasoning
enhanced = enhanced.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
const channelId = raw.channel || raw.channel_id || 'C0AKJ788GJK';
const userId    = raw.user_id || raw.user    || '';
const clientId  = 'n8n-vid-' + Date.now();
const seed = Math.floor(Math.random() * 1_000_000_000);

// AnimateDiff v3 SD1.5 pipeline → 16-frame MP4 via VHS_VideoCombine
// Requires: v1-5-pruned-emaonly.safetensors (checkpoint) + v3_sd15_mm.ckpt (motion model)
const workflow = {
  // 1. Load SD1.5 checkpoint
  "1": {
    "inputs": { "ckpt_name": "v1-5-pruned-emaonly.safetensors" },
    "class_type": "CheckpointLoaderSimple"
  },
  // 2. Load AnimateDiff v3 motion model
  "2": {
    "inputs": {
      "model_name": "v3_sd15_mm.ckpt",
      "beta_schedule": "sqrt_linear (AnimateDiff)",
      "model": ["1", 0]
    },
    "class_type": "ADE_AnimateDiffLoaderGen1"
  },
  // 3. Positive prompt
  "3": {
    "inputs": { "text": enhanced, "clip": ["1", 1] },
    "class_type": "CLIPTextEncode"
  },
  // 4. Negative prompt
  "4": {
    "inputs": {
      "text": "blurry, low quality, static, watermark, text, logo, deformed, morphing, distorted face, bad anatomy, extra limbs",
      "clip": ["1", 1]
    },
    "class_type": "CLIPTextEncode"
  },
  // 5. Empty latent (16 frames for ~2 sec at 8fps)
  "5": {
    "inputs": { "width": 512, "height": 512, "batch_size": 16 },
    "class_type": "EmptyLatentImage"
  },
  // 6. KSampler with AnimateDiff-patched model
  "6": {
    "inputs": {
      "seed": seed, "steps": 25, "cfg": 7.5,
      "sampler_name": "euler_ancestral", "scheduler": "normal",
      "denoise": 1.0,
      "model": ["2", 0], "positive": ["3", 0], "negative": ["4", 0],
      "latent_image": ["5", 0]
    },
    "class_type": "KSampler"
  },
  // 7. VAE Decode
  "7": {
    "inputs": { "samples": ["6", 0], "vae": ["1", 2] },
    "class_type": "VAEDecode"
  },
  // 8. Combine frames to H264 MP4 using NVENC (RTX 5070 Ti)
  "8": {
    "inputs": {
      "frame_rate": 8,
      "loop_count": 0,
      "filename_prefix": "n8n_video",
      "format": "video/h264-mp4",
      "pingpong": false,
      "save_output": true,
      "pix_fmt": "yuv420p",
      "crf": 19,
      "save_metadata": true,
      "images": ["7", 0]
    },
    "class_type": "VHS_VideoCombine"
  }
};

return [{ json: { workflow, clientId, channelId, userId, prompt: enhanced } }];

const http = require('http');

function httpGetComfyUI(path) {
  return new Promise((resolve, reject) => {
    const req = http.get({ host: 'host.docker.internal', port: 8188, path }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        try { resolve(JSON.parse(Buffer.concat(chunks).toString())); }
        catch { resolve({}); }
      });
    });
    req.on('error', reject);
  });
}

const promptId  = $input.first().json.prompt_id;
const maxTries  = 90; // 7.5 min max (AnimateDiff takes longer than single image)

for (let i = 0; i < maxTries; i++) {
  await new Promise(r => setTimeout(r, 5000));
  const history = await httpGetComfyUI(`/history/${promptId}`);
  const entry = history[promptId];
  if (entry?.status?.completed) {
    // VHS_VideoCombine outputs ALL files (mp4 + gif preview) under 'gifs' key
    const node = Object.values(entry.outputs || {}).find(o => o.gifs?.length || o.videos?.length || o.images?.length);
    if (node) {
      const allMedia = [...(node.gifs||[]), ...(node.videos||[]), ...(node.images||[])];
      const VIDEO_EXTS = ['mp4','webm','mkv'];
      // Prefer MP4/video first, then GIF, then anything else
      const media =
        allMedia.find(m => VIDEO_EXTS.includes((m.filename||'').split('.').pop().toLowerCase())) ||
        allMedia.find(m => (m.format||'').startsWith('video/')) ||
        allMedia.find(m => (m.filename||'').split('.').pop().toLowerCase() === 'gif') ||
        allMedia[0];
      if (!media) continue;
      const buildData = $('Build ComfyUI Payload').first().json;
      const ext = (media.filename || '').split('.').pop().toLowerCase();
      const fmtField = (media.format || '');
      const mediaType = (VIDEO_EXTS.includes(ext) || fmtField.startsWith('video/')) ? 'video'
                      : (ext === 'gif' ? 'gif' : 'image');
      return [{ json: {
        promptId,
        filename:  media.filename,
        subfolder: media.subfolder || '',
        type:      media.type || 'output',
        channelId: buildData.channelId,
        userId:    buildData.userId,
        prompt:    buildData.prompt,
        mediaType
      }}];
    }
  }
}
throw new Error('ComfyUI generation timed out after 7.5 minutes');

const https = require('https');
const http = require('http');

function slackApi(path, body) {
  return new Promise((resolve, reject) => {
    const data = JSON.stringify(body);
    const req = https.request({
      method: 'POST', hostname: 'slack.com', path: `/api/${path}`,
      headers: {
        'Authorization': `Bearer ${$env.SLACK_BOT_TOKEN}`,
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(data)
      }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        try { resolve(JSON.parse(Buffer.concat(chunks).toString())); }
        catch { resolve({}); }
      });
    });
    req.on('error', reject);
    req.write(data);
    req.end();
  });
}

function slackUploadFile(channelId, filename, fileData, title, comment) {
  return new Promise((resolve, reject) => {
    const boundary = '----n8nBoundary' + Date.now();
    const parts = [];
    parts.push(`--${boundary}\r\nContent-Disposition: form-data; name="channels"\r\n\r\n${channelId}`);
    parts.push(`--${boundary}\r\nContent-Disposition: form-data; name="title"\r\n\r\n${title}`);
    parts.push(`--${boundary}\r\nContent-Disposition: form-data; name="initial_comment"\r\n\r\n${comment}`);
    parts.push(`--${boundary}\r\nContent-Disposition: form-data; name="filename"\r\n\r\n${filename}`);
    const fileHeader = `--${boundary}\r\nContent-Disposition: form-data; name="file"; filename="${filename}"\r\nContent-Type: video/mp4\r\n\r\n`;
    const footer = `\r\n--${boundary}--\r\n`;
    const prefix = parts.join('\r\n') + '\r\n' + fileHeader;
    const prefixBuf = Buffer.from(prefix);
    const footerBuf = Buffer.from(footer);
    const body = Buffer.concat([prefixBuf, fileData, footerBuf]);

    const req = https.request({
      method: 'POST', hostname: 'slack.com', path: '/api/files.upload',
      headers: {
        'Authorization': `Bearer ${$env.SLACK_BOT_TOKEN}`,
        'Content-Type': `multipart/form-data; boundary=${boundary}`,
        'Content-Length': body.length
      }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        try { resolve(JSON.parse(Buffer.concat(chunks).toString())); }
        catch { resolve({}); }
      });
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
}

function downloadFromComfyUI(filename, subfolder, type) {
  return new Promise((resolve, reject) => {
    const path = `/view?filename=${encodeURIComponent(filename)}&subfolder=${encodeURIComponent(subfolder)}&type=${type}`;
    const req = http.get({ host: 'host.docker.internal', port: 8188, path }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => resolve(Buffer.concat(chunks)));
    });
    req.on('error', reject);
  });
}

const ctx = $input.first().json;
const channelId = ctx.channelId || 'C0AKW7W9ZPX';
const prompt = ctx.prompt || '';
const mediaType = ctx.mediaType || 'video';

if (mediaType === 'video') {
  // For MP4 video: download from ComfyUI and upload directly to Slack
  const fileData = await downloadFromComfyUI(ctx.filename, ctx.subfolder || '', ctx.type || 'output');
  const title = `:film_frames: Video: ${prompt.slice(0, 80)}`;
  const comment = `:film_frames: *Video Generated*\n*Prompt:* ${prompt.slice(0, 200)}\n_AnimateDiff v3 SD1.5 16-frame MP4 on RTX 5070 Ti \u00b7 ${new Date().toLocaleTimeString()}_`;
  const result = await slackUploadFile(channelId, ctx.filename || 'video.mp4', fileData, title, comment);
  if (!result.ok) {
    throw new Error(`Slack upload failed: ${result.error || JSON.stringify(result)}`);
  }
  return [{ json: { ok: true, channel: channelId, file_id: result.file?.id } }];
} else {
  // Fallback for GIF/image: use image block with preview URL
  const ngrokBase = ($env.WEBHOOK_URL || '').replace(/\/$/, '');
  const imageUrl = `${ngrokBase}/webhook/preview-comfyui?filename=${encodeURIComponent(ctx.filename)}&subfolder=${encodeURIComponent(ctx.subfolder || '')}&type=${ctx.type || 'output'}`;
  const titleText = ':film_frames: Video Generated';
  const blocks = [
    { type: 'header', text: { type: 'plain_text', text: titleText } },
    { type: 'section', text: { type: 'mrkdwn', text: `*Prompt:* ${prompt.slice(0, 200)}` } },
    { type: 'image', image_url: imageUrl, alt_text: 'Generated output' },
    { type: 'context', elements: [{ type: 'mrkdwn', text: `_AnimateDiff v3 on RTX 5070 Ti \u00b7 ${new Date().toLocaleTimeString()}_` }] }
  ];
  const result = await slackApi('chat.postMessage', {
    channel: channelId,
    text: `${titleText}: ${prompt.slice(0, 80)}`,
    blocks
  });
  if (!result.ok) {
    throw new Error(`Slack post failed: ${result.error || JSON.stringify(result)}`);
  }
  return [{ json: { ok: true, ts: result.ts, channel: result.channel, channelId } }];
}

// Restore context from Poll Until Done node (HTTP Request dropped it)
const poll = $('Poll Until Done').first().json;
const item = $input.first();
return [{
  json: {
    channelId: poll.channelId || '',
    filename: poll.filename || 'file',
    prompt: poll.prompt || '',
    uploadComment: poll.uploadComment || '{}'
  },
  binary: item.binary
}];
